record_types.code:
type Bitmap_Color is record
   Alpha : UInt8;
   Red   : UInt8;
   Green : UInt8;
   Blue  : UInt8;
end record;

type Point is record
   X : Natural;
   Y : Natural;
end record;

type Rect is record
   Position : Point;
   Width    : Natural;
   Height   : Natural;
end record;

